 # 找到目标日期或之前最近的交易日\n        bars_before_target = bars[bars.index <= target_date]\n        \n        if len(bars_before_target) < 30:\n            failed_stocks.append(f\"{code}: 目标日期前数据不足\")\n            continue\n        \n        # 取最近30个交易日\n        recent_30 = bars_before_target.tail(30)\n        \n        # 计算20日布林带（使用最近30日中的最后一天）\n        if len(recent_30) < 20:\n            failed_stocks.append(f\"{code}: 不足20日数据\")\n            continue\n        \n        # 取最近20日收盘价\n        close_20 = recent_30['close'].tail(20)\n        \n        # 计算布林带\n        middle = close_20.mean()  # 中轨：20日SMA\n        std = close_20.std()       # 20日标准差\n        upper = middle + 2 * std   # 上轨\n        lower = middle - 2 * std   # 下轨\n        \n        # 计算布林带宽度\n        if middle > 0:\n            bandwidth = (upper - lower) / middle\n            \n            # 判断是否处于盘整（宽度 < 5%）\n            if bandwidth < 0.05:\n                squeeze_count += 1\n        \n        valid_stocks += 1\n        \n        if (valid_stocks) % 100 == 0:\n            print(f\"已处理 {valid_stocks} 只股票...\")\n            \n    except Exception as e:\n        failed_stocks.append(f\"{code}: {str(e)}\")\n        continue\n\nprint(f\"\\n处理完成！\")\nprint(f\"有效股票数: {valid_stocks}\")\nprint(f\"符合盘整条件: {squeeze_count}\")\nprint(f\"失败股票数: {len(failed_stocks)}\")\n\n# 计算占比\nif valid_stocks > 0:\n    ratio = (squeeze_count / valid_stocks) * 100\nelse:\n    ratio = 0.0\n\n# 输出结果\nresult_dir = \"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_06_bollinger_squeeze/independent/ga\"\noutput_file = f\"{result_dir}/bollinger_count.txt\"\n\nresult_text = f\"\"\"符合条件的股票数量: {squeeze_count}\n占创业板比例: {ratio:.2f}%\"\"\"\n\nwith open(output_file, 'w', encoding='utf-8') as f:\n    f.write(result_text)\n\nprint(f\"\\n结果已写入: {output_file}\")\nprint(result_text)\n\n# 输出部分失败信息（前10个）\nif failed_stocks:\n    print(f\"\\n部分失败股票（前10个）:\")\n    for fail in failed_stocks[:10]:\n 