3\n\"\"\"\n使用mootdx获取数据来统计MACD柱状图趋势\n\"\"\"\nimport pandas as pd\nimport numpy as np\nfrom mootdx.quotes import Quotes\nimport time\n\n\ndef compute_macd(close, fast=12, slow=26, signal=9):\n    \"\"\"\n    计算MACD指标\n    返回: DataFrame with columns: diff, dea, histogram\n    \"\"\"\n    ema_fast = close.ewm(span=fast, adjust=False).mean()\n    ema_slow = close.ewm(span=slow, adjust=False).mean()\n    diff = ema_fast - ema_slow\n    dea = diff.ewm(span=signal, adjust=False).mean()\n    histogram = diff - dea\n    return pd.DataFrame({'diff': diff, 'dea': dea, 'histogram': histogram},\n                        index=close.index)\n\n\ndef check_histogram_negative_to_positive_with_growth(histogram_series, window=60):\n    \"\"\"\n    检查在window天内，histogram是否出现从负转正后连续5天递增的情况\n    返回: True/False\n    \"\"\"\n    # 只分析最近window天\n    if len(histogram_series) < window:\n        hist_values = histogram_series.values\n    else:\n        hist_values = histogram_series.iloc[-window:].values\n\n    # 搜索从负转正的位置\n    for i in range(len(hist_values) - 6):  # 需要至少6天（转正当天+后续5天）\n        # 检查是否从负转正（前一天<0，当天>0）\n        if hist_values[i] < 0 and hist_values[i + 1] > 0:\n            # 检查从转正后连续5天是否严格递增\n            is_consecutive_increasing = True\n            for j in range(5):\n                if hist_values[i + 1 + j + 1] <= hist_values[i + 1 + j]:\n                    is_consecutive_increasing = False\n                    break\n\n            if is_consecutive_increasing:\n                return True\n\n    return False\n\n\ndef get_stock_data_mootdx(symbol, client):\n    \"\"\"\n    使用mootdx获取股票K线数据\n    \"\"\"\n    try:\n        # 获取90个交易日数据\n        bars = client.bars(symbol=symbol, frequency=9, offset=90)\n\n        if bars is None or len(bars) < 60:\n            return None\n\n        # 确保按日期升序排列\n        bars = bars.sort_values('date').reset_index(drop=True)\n\n        return bars\n\n    except Exception as e:\n        return None\n\n\ndef analyze_stock(symbol, client):\n    \"\"\"\n    分析单只股票的MACD histogram趋势\n    返回: 是否符合条件\n    \"\"\"\n    try:\n        df = get_stock_data_mootdx(symbol, client)\n\n        if df is None or len(df) < 60:\n            return False\n\n        # 计算MACD\n        close = df['close']\n        macd_df = compute_macd(close)\n\n        # 检查histogram从负转正后连续5天递增\n        result = check_histogram_negative_to_positive_with_growth(\n            macd_df['histogram'], window=60\n        )\n\n        return result\n\n    except Exception as e:\n        return False\n\n\ndef get_chinext_stocks_mootdx(client):\n    \"\"\"\n    获取创业板股票列表\n    \"\"\"\n    try:\n        # 获取深圳市场股票列表\n        stocks = client.stocks(market=0)  # 0=深圳\n\n        if stocks is None or len(stocks) == 0:\n            return []\n\n        # 筛选创业板（代码以300或301开头）\n        chinext = stocks[stocks['code'].str.startswith(('300', '301'))]\n\n        return chinext['code'].tolist()\n\n    except Exception as e:\n        print(f\"获取股票列表失败: {e}\")\n        return []\n\n\ndef main():\n    print(\"初始化mootdx客户端...\")\n\n    try:\n        client = Quotes.factory(market='std')\n        print(\"客户端初始化成功\")\n    except Exception as e:\n        print(f\"客户端初始化失败: {e}\")\n        return\n\n    print(\"开始获取创业板股票列表...\")\n    stock_codes = get_chinext_stocks_mootdx(client)\n\n    if not stock_codes:\n        print(\"无法获取股票列表，退出\")\n        return\n\n    print(f\"创业板股票总数: {len(stock_codes)}\")\n    print(\"开始分析股票...\")\n\n    count = 0\n    total = len(stock_codes)\n    processed = 0\n    failed = 0\n\n    for idx, code in enumerate(stock_codes):\n        if (idx + 1) % 50 == 0:\n            print(f\"进度: {idx + 1}/{total}, 已处理: {processed}, 失败: {failed}, 符合条件: {count}\")\n\n        result = analyze_stock(code, client)\n\n        if result is None:\n            failed += 1\n        else:\n            processed += 1\n            if result:\n                count += 1\n                print(f\"  ✓ {code} 符合条件\")\n\n        # 避免请求过快\n        time.sleep(0.05)\n\n    print(f\"\\n分析完成！\")\n    print(f\"总共处理: {processed} 只股票\")\n    print(f\"失败: {failed} 只股票\")\n    print(f\"符合条件的股票总数: {count}\")\n\n    # 写入结果文件\n    with open('macd_strength_count.txt', 'w', encoding='utf-8') as f:\n        f.write(f\"符合条件的股票总数: {count}\\n\")\n\n    print(\"结果已写入 macd_strength_count.txt\")\n\n\nif __name__ == \"__main__\":\n    main()\n","numLines":176,"startLine":1,"totalLines":176}}}
