{"type":"assistant","message":{"content":[{"id":"tooluse_ZGd4rtDMrvYV2Jdn0eLjLX","input":{"file_path":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_06_bollinger_squeeze/revised/claudecode/bollinger_squeeze_v2.py","content":"#!/usr/bin/env python3\n\"\"\"\n统计创业板中截至 2024-08-30 的前30个交易日内，\n有多少只股票的布林带宽度处于盘整状态（< 5%）\n\n注意：mootdx只能获取最近的数据，无法指定历史日期\n因此我们获取足够多的历史数据，然后筛选到2024-08-30\n\"\"\"\nimport pandas as pd\nimport numpy as np\nfrom mootdx.quotes import Quotes\nimport time\nfrom datetime import datetime\n\n\ndef calculate_bollinger_bands(close_prices, window=20):\n    \"\"\"\n    计算布林带指标\n    中轨 = 20日SMA\n    上轨 = 中轨 + 2*标准差\n    下轨 = 中轨 - 2*标准差\n    \"\"\"\n    if len(close_prices) < window:\n        return None, None, None\n\n    # 计算中轨（20日简单移动平均）\n    middle = close_prices.rolling(window=window).mean()\n\n    # 计算20日标准差\n    std = close_prices.rolling(window=window).std()\n\n    # 计算上轨和下轨\n    upper = middle + 2 * std\n    lower = middle - 2 * std\n\n    return upper, middle, lower\n\n\ndef calculate_bollinger_width(upper, middle, lower):\n    \"\"\"\n    计算布林带宽度 = (上轨 - 下轨) / 中轨\n    \"\"\"\n    if middle == 0 or pd.isna(middle) or pd.isna(upper) or pd.isna(lower):\n        return None\n\n    width = (upper - lower) / middle\n    return width\n\n\ndef get_stock_data(symbol, client, days=500):\n    \"\"\"\n    获取股票K线数据\n    获取足够多的历史数据以覆盖2024-08-30\n    \"\"\"\n    try:\n        # 获取日线数据，frequency=9表示日线\n        bars = client.bars(symbol=symbol, frequency=9, offset=days)\n\n        if bars is None or len(bars) < 50:\n            return None\n\n        # bars已经有datetime索引，直接使用\n        # 按日期升序排列\n        bars = bars.sort_index()\n\n        return bars\n\n    except Exception as e:\n        return None\n\n\ndef check_bollinger_squeeze(symbol, client, target_date='2024-08-30'):\n    \"\"\"\n    检查股票在目标日期的布林带宽度是否 < 5%\n    \"\"\"\n    try:\n        # 获取数据\n        df = get_stock_data(symbol, client, days=500)\n\n        if df is None or len(df) < 50:\n            return None\n\n        # 将datetime索引转换为日期字符串进行比较\n        df['date_str'] = df.index.strftime('%Y-%m-%d')\n\n        # 找到目标日期或之前最近的交易日\n        target_data = df[df['date_str'] <= target_date]\n\n        if len(target_data) < 50:\n            return None\n\n        # 只使用目标日期之前的数据\n        close = target_data['close']\n\n        # 计算布林带\n        upper, middle, lower = calculate_bollinger_bands(close, window=20)\n\n        if upper is None:\n            return None\n\n        # 获取最新一天（即目标日期或之前）的布林带数据\n        latest_upper = upper.iloc[-1]\n        latest_middle = middle.iloc[-1]\n        latest_lower = lower.iloc[-1]\n\n        # 计算宽度\n        width = calculate_bollinger_width(latest_upper, latest_middle, latest_lower)\n\n        if width is None:\n            return None\n\n        # 判断是否处于盘整（宽度 < 5%）\n        is_squeeze = width < 0.05\n\n        return is_squeeze\n\n    except Exception as e:\n        return None\n\n\ndef get_chinext_stocks(client):\n    \"\"\"\n    获取创业板股票列表（代码以300或301开头）\n    \"\"\"\n    try:\n        # 获取深圳市场股票列表，market=0表示深圳\n        stocks = client.stocks(market=0)\n\n        if stocks is None or len(stocks) == 0:\n            return []\n\n        # 筛选创业板股票\n        chinext = stocks[stocks['code'].str.startswith(('300', '301'))]\n\n        return chinext['code'].tolist()\n\n    except Exception as e:\n        print(f\"获取股票列表失败: {e}\")\n        return []\n\n\ndef main():\n    print(\"初始化mootdx客户端...\")\n\n    try:\n        client = Quotes.factory(market='std')\n        print(\"客户端初始化成功\")\n    except Exception as e:\n        print(f\"客户端初始化失败: {e}\")\n        return\n\n    print(\"获取创业板股票列表...\")\n    stock_codes = get_chinext_stocks(client)\n\n    if not stock_codes:\n        print(\"无法获取股票列表\")\n        return\n\n    total_stocks = len(stock_codes)\n    print(f\"创业板股票总数: {total_stocks}\")\n    print(\"开始计算布林带宽度...\")\n\n    squeeze_count = 0\n    valid_count = 0\n    failed_count = 0\n\n    for idx, code in enumerate(stock_codes):\n        if (idx + 1) % 100 == 0:\n            print(f\"进度: {idx + 1}/{total_stocks}, 有效: {valid_count}, 失败: {failed_count}, 盘整: {squeeze_count}\")\n\n        result = check_bollinger_squeeze(code, client)\n\n        if result is None:\n            failed_count += 1\n        else:\n            valid_count += 1\n            if result:\n                squeeze_count += 1\n\n        # 避免请求过快\n        time.sleep(0.05)\n\n    print(f\"\\n处理完成！\")\n    print(f\"总股票数: {total_stocks}\")\n    print(f\"有效股票数: {valid_count}\")\n    print(f\"失败股票数: {failed_count}\")\n    print(f\"符合盘整条件: {squeeze_count}\")\n\n    # 计算占比（基于有效股票数）\n    if valid_count > 0:\n        ratio = (squeeze_count / valid_count) * 100\n    else:\n        ratio = 0.0\n\n    # 写入结果文件\n    output_path = '/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_06_bollinger_squeeze/revised/claudecode/bollinger_count.txt'\n\n    with open(output_path, 'w', encoding='utf-8') as f:\n        f.write(f\"符合条件的股票数量: {squeeze_count}\\n\")\n        f.write(f\"占创业板比例: {ratio:.2f}%\\n\")\n\n    print(f\"\\n结果已写入: {output_path}\")\n    print(f\"符合条件的股票数量: {squeeze_count}\")\n    print(f\"占创业板比例: {ratio:.2f}%\")\n\n\nif __name__ == \"__main__\":\n    main()\n"},"name":"Write","type":"tool_use"}],"id":"f845d67a-d140-4afc-8630-05889066e761","model":"claude-sonnet-4-6","role":"assistant","stop_reason":null,"stop_sequence":null,"type":"message","usage":{"cache_creation_input_tokens":1226,"cache_read_input_tokens":0,"input_tokens":19009,"output_tokens":0},"context_management":null},"parent_tool_use_id":null,"session_id":"0e443fdf-1e41-4d22-95d7-ad9c1c1cb246","uuid":"9be3d11f-3e68-4650-bebd-95011f5dc140"}
